solutions.javascript:
// Solution
app.get('/users/:id', (req, res) => {
  const id = parseInt(req.params.id);
  if (isNaN(id) || id <= 0) {
    res.status(404).json({ error: 'Invalid user id' });
  } else {
    // Query the database for the user with the given id
    const user = { id, name: 'John Doe' };
    res.json(user);
  }
})
